#include <stdio.h>
#include <string.h>

int main() {
    int T, N, P, a, b;
    char S[1000005];

    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %s", &N, &P, S);
        a = b = 0;

        for (int i = 0; i < N; i++) {
            if (S[i] == 'a')
                a++;
            else
                b++;
        }

        while (P > 0 && b > 0) {
            P--;
            b--;
            a++;
        }

        for (int i = 0; i < N; i++) {
            if (i < a)
                S[i] = 'a';
            else if (i < a + b)
                S[i] = 'b';
            else
                S[i] = 'a';
        }

        printf("%s\n", S);
    }

    return 0;
}

