code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T, N, P, a, b;
        String S;

        T = sc.nextInt();
        while (T-- > 0) {
            N = sc.nextInt();
            P = sc.nextInt();
            S = sc.next();
            a = b = 0;

            for (int i = 0; i < N; i++) {
                if (S.charAt(i) == 'a')
                    a++;
                else
                    b++;
            }

            while (P > 0 && b > 0) {
                P--;
                b--;
                a++;
            }

            for (int i = 0; i < N; i++) {
                if (i < a)
                    S = S.substring(0, i) + 'a' + S.substring(i + 1);
                else if (i < a + b)
                    S = S.substring(0, i) + 'b' + S.substring(i + 1);
                else
                    S = S.substring(0, i) + 'a' + S.substring(i + 1);
            }

            System.out.println(S);
        }
    }
}

