let T = parseInt(input.shift());

while (T--) {
    let [N, P] = input.shift().split(' ').map(Number);
    let S = input.shift().trim();
    let a = b = 0;

    for (let c of S) {
        if (c == 'a')
            a++;
        else
            b++;
    }

    while (P > 0 && b > 0) {
        P--;
        b--;
        a++;
    }

    for (let i = 0; i < N; i++) {
        if (i < a)
            S = S.slice(0, i) + 'a' + S.slice(i + 1);
        else if (i < a + b)
            S = S.slice(0, i) + 'b' + S.slice(i + 1);
        else
            S = S.slice(0, i) + 'a' + S.slice(i + 1);
    }

    console.log(S);
